import type React from 'react';
export type { StyleProps, LiteralUnion, ElementOf } from '@universe-design/react-utilities';
export type TKeyValueMap<V> = {
    [x in React.Key]: V;
};
export type TAction<T, P> = {
    type: T;
    payload: P;
};
type UnionKeys<T> = T extends T ? keyof T : never;
type StrictUnionHelper<T, TAll> = T extends any ? T & Partial<Record<Exclude<UnionKeys<TAll>, keyof T>, never>> : never;
export type StrictUnion<T> = StrictUnionHelper<T, T>;
interface Callable<R> {
    (...args: any[]): R;
}
export type GenericReturnType<R, X> = X extends Callable<R> ? R : never;
export type GetPopupContainer = string | HTMLElement | (() => HTMLElement) | false;
export interface HookSharedOptions {
    /**
     * 是否跳过 hook 逻辑
     */
    skipped?: boolean;
}
export type { StylexProps } from '@universe-design/stylex/react';
export type ListScrollAlign = 'top' | 'bottom' | 'auto';
export interface ListScrollConfig {
    /**
     * 跟可视区域的对齐方式 （`top`: 顶部与顶部对齐，`bottom`: 顶部和底部对齐，`auto`: 根据与可视区域的相对位置决定）
     */
    align?: ListScrollAlign;
    /**
     * 偏移量
     */
    offset?: number;
}
